sql:
SELECT COUNT(disaster_id) 
FROM disasters
WHERE province_id = (SELECT province_id FROM provinces WHERE province_name = 'Batangas');

SELECT COUNT(DISTINCT province_id) 
FROM disaster_impact 
WHERE impact_level IN ('moderate', 'severe');

SELECT COUNT(*) 
FROM disasters 
WHERE province_id = 0 AND disaster_type_id = 1;

SELECT provinces.province_name, disasters.disaster_description
FROM provinces
INNER JOIN disasters ON provinces.province_id = disasters.province_id;

SELECT DISTINCT p.province_name
FROM provinces p
JOIN disasters d ON p.province_id = d.province_id;

external_knowledge:
Large provinces: those with a population over 1 million;
Significant impact: disasters where more than 10,000 people were affected;
Typical cost of damage: average damage cost in million PHP;
Time frame: between 2010 and 2022.

- "regions" refers to 'provinces'.;
- "notable surge in incidents" implies counting disaster occurrences. ;
- "since the beginning of last year" means from January 1, 2023. ;
